import{_ as t,o,c as a,ag as r}from"./chunks/framework.BYehg5q7.js";const u=JSON.parse('{"title":"AI Providers","description":"","frontmatter":{},"headers":[],"relativePath":"guide/ai-providers.md","filePath":"guide/ai-providers.md","lastUpdated":1773484209000}'),s={name:"guide/ai-providers.md"};function i(l,e,d,n,c,h){return o(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="ai-providers" tabindex="-1">AI Providers <a class="header-anchor" href="#ai-providers" aria-label="Permalink to &quot;AI Providers&quot;">​</a></h1><p>getbased supports four AI backends for PDF import, chat, and dashboard AI features. You can switch between them at any time in <strong>Settings → AI</strong>.</p><h2 id="which-features-need-an-ai-provider" tabindex="-1">Which Features Need an AI Provider? <a class="header-anchor" href="#which-features-need-an-ai-provider" aria-label="Permalink to &quot;Which Features Need an AI Provider?&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Feature</th><th>Requires AI?</th></tr></thead><tbody><tr><td>PDF import</td><td>Yes</td></tr><tr><td>AI chat panel</td><td>Yes</td></tr><tr><td>Focus card (dashboard insight)</td><td>Yes</td></tr><tr><td>Health status dots on context cards</td><td>Yes</td></tr><tr><td>AI-generated card tips</td><td>Yes</td></tr><tr><td>Charts, tables, trend alerts</td><td>No</td></tr><tr><td>Manual entry</td><td>No</td></tr><tr><td>JSON export / import</td><td>No</td></tr><tr><td>Correlations, compare dates</td><td>No</td></tr><tr><td>Marker glossary</td><td>No</td></tr></tbody></table><p>All non-AI features work fully without any provider configured.</p><h2 id="the-four-providers" tabindex="-1">The Four Providers <a class="header-anchor" href="#the-four-providers" aria-label="Permalink to &quot;The Four Providers&quot;">​</a></h2><h3 id="openrouter-recommended" tabindex="-1">OpenRouter (Recommended) <a class="header-anchor" href="#openrouter-recommended" aria-label="Permalink to &quot;OpenRouter (Recommended)&quot;">​</a></h3><p>A model marketplace that gives you access to 200+ models — Claude, GPT, Gemini, DeepSeek, Grok, Qwen, and more — through a single account. getbased shows a curated list of the latest medically capable models and displays live pricing for each. OpenRouter is the recommended provider and appears as the first tab in Settings.</p><p><strong>Setup — OAuth (easiest):</strong></p><ol><li>In Settings → AI Provider, select <strong>OpenRouter</strong></li><li>Click <strong>Connect with OpenRouter</strong></li><li>Authorize getbased on the OpenRouter site</li><li>You&#39;re connected — no API key needed</li></ol><p><strong>Setup — API key:</strong></p><ol><li>Get an API key at <a href="https://openrouter.ai" target="_blank" rel="noreferrer">openrouter.ai</a></li><li>In Settings → AI Provider, select <strong>OpenRouter</strong></li><li>Paste your API key</li><li>Choose a model from the curated dropdown, or type any model ID into the custom input field below it (a health check confirms connectivity)</li></ol><div class="tip custom-block"><p class="custom-block-title">One-click connect</p><p>The OAuth button also appears in the chat setup guide when no provider is configured, making it easy for new users to get started.</p></div><h3 id="anthropic" tabindex="-1">Anthropic <a class="header-anchor" href="#anthropic" aria-label="Permalink to &quot;Anthropic&quot;">​</a></h3><p>Direct access to Claude models via the Anthropic API. Claude was specifically designed to be helpful with medical and scientific information, making it an accurate choice for interpreting lab data.</p><p><strong>Setup:</strong></p><ol><li>Get an API key at <a href="https://console.anthropic.com" target="_blank" rel="noreferrer">console.anthropic.com</a></li><li>In Settings → AI Provider, select <strong>Anthropic</strong></li><li>Paste your API key</li><li>Choose a model from the dropdown (the app fetches available models automatically)</li></ol><div class="tip custom-block"><p class="custom-block-title">Pay per use</p><p>Anthropic charges per token. A typical PDF import costs a few cents. Chat responses cost fractions of a cent each.</p></div><h3 id="venice-ai-best-for-privacy" tabindex="-1">Venice AI (Best for privacy) <a class="header-anchor" href="#venice-ai-best-for-privacy" aria-label="Permalink to &quot;Venice AI (Best for privacy)&quot;">​</a></h3><p>A privacy-focused cloud provider where your conversations and data are not stored or logged on their servers. Venice also proxies access to GPT, Grok, and DeepSeek models.</p><p><strong>Setup:</strong></p><ol><li>Get an API key at <a href="https://venice.ai" target="_blank" rel="noreferrer">venice.ai</a></li><li>In Settings → AI Provider, select <strong>Venice</strong></li><li>Paste your API key</li><li>Choose a model from the dropdown</li></ol><h3 id="local-ai-fully-local" tabindex="-1">Local AI (Fully local) <a class="header-anchor" href="#local-ai-fully-local" aria-label="Permalink to &quot;Local AI (Fully local)&quot;">​</a></h3><p>Run a language model entirely on your own machine. Nothing is sent over the network — not even for PDF import. Local AI connects via the standard OpenAI-compatible API (<code>/v1/chat/completions</code>), which is supported by all major local servers:</p><ul><li><a href="https://ollama.com" target="_blank" rel="noreferrer">Ollama</a> — easiest setup, pull models from the command line</li><li><a href="https://lmstudio.ai" target="_blank" rel="noreferrer">LM Studio</a> — GUI-based, drag-and-drop model loading</li><li><a href="https://jan.ai" target="_blank" rel="noreferrer">Jan</a> — open-source desktop app</li><li>llama.cpp, LocalAI, and others</li></ul><p><strong>Setup:</strong></p><ol><li>Install and start any local AI server</li><li>Load a model (e.g., in Ollama: <code>ollama pull llama3.2</code>)</li><li>In Settings → AI Provider, select <strong>Local</strong></li><li>Enter your server URL (default: <code>http://localhost:11434</code>)</li><li>Click <strong>Test</strong> — the app auto-discovers available models</li><li>Add an API key if your server requires one (most don&#39;t)</li></ol><div class="tip custom-block"><p class="custom-block-title">Local AI also handles PII stripping</p><p>When enabled in Settings → Privacy, your local server is used to intelligently strip personal information from PDFs before analysis. See <a href="./pii-obfuscation.html">PII Obfuscation</a> for details.</p></div><div class="tip custom-block"><p class="custom-block-title">Cross-origin access requires OLLAMA_ORIGINS</p><p>Ollama blocks requests from web pages by default. When using getbased (whether hosted or local dev server), start Ollama with:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>OLLAMA_ORIGINS=* ollama serve</span></span></code></pre></div><p>LM Studio, Jan, and other servers typically allow all origins by default.</p></div><div class="warning custom-block"><p class="custom-block-title">HTTPS limits Local AI to localhost</p><p>The hosted app at <code>app.getbased.health</code> is served over HTTPS. Browsers block HTTPS pages from making requests to plain HTTP servers on your LAN (mixed content). This means <strong>Local AI must run on the same machine</strong> — only <code>localhost</code> / <code>127.0.0.1</code> will work. If you need to reach a server on another device, use the local dev server (<code>node dev-server.js</code>) which runs over HTTP.</p></div><div class="tip custom-block"><p class="custom-block-title">Model Advisor</p><p>When connected to Ollama, the app detects your GPU and shows a <strong>Model Advisor</strong> panel below the model dropdown. Each installed model gets a fitness rating for lab analysis (★ Recommended, Capable, Underpowered, or Inadequate) and a VRAM fit check. If none of your models are recommended, it suggests the best one to pull for your hardware. For remote Ollama servers, enter the server&#39;s VRAM manually to get accurate recommendations.</p></div><div class="warning custom-block"><p class="custom-block-title">Use a capable model</p><p>Models under 14B parameters struggle with accurate marker extraction from complex lab PDFs. The Model Advisor in Settings will tell you exactly which of your installed models are suitable — look for the ★ Recommended badge. When in doubt, <code>ollama pull qwen2.5:14b</code> is the best value for reliable local lab parsing.</p></div><h2 id="recommended-models" tabindex="-1">Recommended Models <a class="header-anchor" href="#recommended-models" aria-label="Permalink to &quot;Recommended Models&quot;">​</a></h2><p>All providers show a tiered model dropdown with two groups:</p><ul><li><strong>★ Recommended</strong> — the latest, most capable models for lab interpretation (sorted first)</li><li><strong>Other</strong> — all remaining available models</li></ul><p>Recommended models are chosen for accuracy with medical/scientific data. You can use any model, but recommended ones produce the most reliable results.</p><h2 id="model-consistency" tabindex="-1">Model Consistency <a class="header-anchor" href="#model-consistency" aria-label="Permalink to &quot;Model Consistency&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Use the same model across imports</p><p>When you import lab PDFs, the AI generates marker keys (like <code>biochemistry.glucose</code>) to map results. Different models may generate slightly different keys for the same marker. Switching models between imports can cause the same marker to appear as two separate entries.</p><p>For best results, pick a model and stick with it for all your imports. If you do switch, getbased runs a pre-flight check before each import and warns you if your model has changed since the last import.</p></div><h2 id="how-much-does-it-cost" tabindex="-1">How Much Does It Cost? <a class="header-anchor" href="#how-much-does-it-cost" aria-label="Permalink to &quot;How Much Does It Cost?&quot;">​</a></h2><p>AI providers charge you based on how much text you send and receive — but the amounts are tiny. getbased shows the exact cost of every interaction in the chat panel, so you always know what you&#39;re spending.</p><p>Here&#39;s what real usage costs with the recommended models:</p><table tabindex="0"><thead><tr><th>Model</th><th>Provider</th><th>Import a lab PDF</th><th>Chat message</th><th>First-time setup*</th><th>Ongoing month**</th></tr></thead><tbody><tr><td>Claude Sonnet 4.6</td><td>Anthropic / OpenRouter</td><td>~$0.04</td><td>~$0.02</td><td><strong>~$1.00</strong></td><td><strong>~$0.50</strong></td></tr><tr><td>GPT 5.2</td><td>OpenRouter / Venice</td><td>~$0.03</td><td>~$0.02</td><td><strong>~$0.80</strong></td><td><strong>~$0.45</strong></td></tr><tr><td>Gemini 3 Pro</td><td>OpenRouter / Venice</td><td>~$0.03</td><td>~$0.01</td><td><strong>~$0.60</strong></td><td><strong>~$0.35</strong></td></tr><tr><td>Grok 4</td><td>OpenRouter / Venice</td><td>~$0.01</td><td>~$0.005</td><td><strong>~$0.25</strong></td><td><strong>~$0.15</strong></td></tr><tr><td>Any local model</td><td>Local AI (Ollama, LM Studio)</td><td>Free</td><td>Free</td><td><strong>Free</strong></td><td><strong>Free</strong></td></tr></tbody></table><p>* <em>First-time setup: importing your first labs + setting up your profile through chat (health goals, context cards, interpretive lens) — typically 3–5 imports and 30+ chat messages.</em></p><p>** <em>Ongoing month: 2–3 lab imports, 20–30 chat messages, dashboard AI features (focus card, health dots). Heavy users who chat daily may spend 2–3x more.</em></p><div class="tip custom-block"><p class="custom-block-title">No surprises</p><p>Every AI response in getbased shows its cost right below the message. You can see exactly what each import and chat message costs as you use the app. Most users spend <strong>well under $1/month</strong>. If your credits run out, getbased shows a clear message with a link to add more.</p></div><div class="tip custom-block"><p class="custom-block-title">Free option</p><p>Run a local model with <a href="https://ollama.com" target="_blank" rel="noreferrer">Ollama</a>, <a href="https://lmstudio.ai" target="_blank" rel="noreferrer">LM Studio</a>, or <a href="https://jan.ai" target="_blank" rel="noreferrer">Jan</a> and pay nothing. You&#39;ll need 8GB+ VRAM (or a Mac with 16GB+ unified memory) for capable models. The Model Advisor in Settings shows exactly what fits your hardware.</p></div><h2 id="switching-providers" tabindex="-1">Switching Providers <a class="header-anchor" href="#switching-providers" aria-label="Permalink to &quot;Switching Providers&quot;">​</a></h2><p>You can switch providers at any time in Settings without losing any data. Your API keys are stored locally in your browser and are never sent to getbased servers.</p>',48)])])}const m=t(s,[["render",i]]);export{u as __pageData,m as default};
